import json

def main(inputs):
    required = ['ftp_config', 'db_connection', 'api_key', 'monitoring_platform_url']
    missing = [field for field in required if not inputs.get(field)]
    if missing:
        return {'status': 'error', 'message': f'缺少必要参数: {missing}'}
    return {'status': 'success', 'message': '参数检查通过'}

import json
import ftplib
from io import BytesIO

def main(ftp_config):
    try:
        config = json.loads(ftp_config)
        ftp = ftplib.FTP(config['host'])
        ftp.login(config['username'], config['password'])
        ftp.cwd(config['directory'])
        files = [f for f in ftp.nlst() if f.endswith('.csv')]
        ftp.quit()
        return {
            'status': 'success',
            'files': files,
            'total_files': len(files)
        }
    except Exception as e:
        return {'status': 'error', 'message': str(e)}

import requests
import pandas as pd

def main(data, api_key):
    df = pd.DataFrame(data)

    if 'ip_address' not in df.columns:
        return {'status': 'success', 'enhanced_data': data, 'geolocated': 0}

    geolocated = 0
    enhanced_records = []

    for _, row in df.iterrows():
        record = row.to_dict()
        ip = record.get('ip_address')

        if ip:
            try:
                # 模拟IP地理位置查询
                response = requests.get(
                    f'http://ip-api.com/json/{ip}',
                    params={'key': api_key},
                    timeout=5
                )
                if response.status_code == 200:
                    geo_data = response.json()
                    record['country'] = geo_data.get('country', '')
                    record['city'] = geo_data.get('city', '')
                    record['isp'] = geo_data.get('isp', '')
                    geolocated += 1
            except:
                pass

        enhanced_records.append(record)

    return {
        'status': 'success',
        'enhanced_data': enhanced_records,
        'geolocated': geolocated
    }

import pandas as pd
from datetime import datetime, timedelta

def main(data):
    df = pd.DataFrame(data)
    anomalies = []

    # 检查异常登录
    if 'action' in df.columns and 'timestamp' in df.columns:
        recent_logins = df[df['action'] == 'LOGIN'].copy()
        if not recent_logins.empty:
            recent_logins['timestamp'] = pd.to_datetime(recent_logins['timestamp'])

            # 查找短时间内多次登录
            recent_logins = recent_logins.sort_values('timestamp')
            for i in range(1, len(recent_logins)):
                time_diff = recent_logins.iloc[i]['timestamp'] - recent_logins.iloc[i-1]['timestamp']
                if time_diff < timedelta(seconds=30):
                    anomaly = {
                        'type': 'rapid_logins',
                        'ip': recent_logins.iloc[i]['ip_address'],
                        'timestamp': str(recent_logins.iloc[i]['timestamp']),
                        'details': '30秒内多次登录尝试'
                    }
                    anomalies.append(anomaly)

    # 检查可疑IP
    if 'country' in df.columns:
        country_counts = df['country'].value_counts()
        suspicious_countries = country_counts[country_counts > 100].index.tolist()
        for country in suspicious_countries:
            anomaly = {
                'type': 'suspicious_country',
                'country': country,
                'count': int(country_counts[country]),
                'details': f'来自{country}的访问次数异常'
            }
            anomalies.append(anomaly)

    return {
        'status': 'success',
        'anomalies': anomalies,
        'anomaly_count': len(anomalies)
    }

import json
import sqlite3
import pandas as pd

def main(data, db_connection):
    try:
        config = json.loads(db_connection)
        df = pd.DataFrame(data)

        # 模拟数据库插入
        conn = sqlite3.connect(':memory:')
        df.to_sql('logs', conn, if_exists='append', index=False)
        inserted = len(df)
        conn.close()

        return {
            'status': 'success',
            'inserted_rows': inserted,
            'message': f'成功插入{inserted}条记录'
        }
    except Exception as e:
        return {'status': 'error', 'message': str(e)}
